import { createPortal } from 'react-dom';
import { BadgeDollarSign, X } from 'lucide-react';

interface Props { isOpen: boolean; value: string; isSubmitting: boolean; error?: string; onClose: () => void; onChange: (value: string) => void; onSubmit: () => void; }
export default function VendorPricingDialog({ isOpen, value, isSubmitting, error, onClose, onChange, onSubmit }: Props) {
  if (!isOpen) return null;
  return createPortal(<div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/45 p-4"><div className="flex w-full max-w-2xl flex-col overflow-hidden rounded-2xl bg-white shadow-2xl"><div className="flex items-center justify-between border-b border-border bg-card px-5 py-4"><div className="flex items-center gap-2 text-[15px] font-extrabold"><BadgeDollarSign size={18} className="text-primary" />Cấu hình giá tham chiếu</div><button onClick={onClose} className="rounded-full p-2 text-muted-foreground hover:bg-muted"><X size={18} /></button></div><div className="p-5"><textarea value={value} onChange={event => onChange(event.target.value)} className="min-h-40 w-full rounded-xl border border-border p-3 text-[13px] outline-none focus:border-primary" placeholder="JSON payload theo contract API /vendors/:id/pricing" />{error && <div className="mt-3 rounded-xl border border-red-200 bg-red-50 p-3 text-[13px] font-bold text-red-600">{error}</div>}</div><div className="flex justify-end gap-3 border-t border-border bg-card p-5"><button onClick={onClose} className="rounded-xl border border-border bg-white px-5 py-3 text-[13px] font-bold text-muted-foreground hover:bg-muted">Hủy</button><button onClick={onSubmit} disabled={isSubmitting} className="rounded-xl bg-primary px-6 py-3 text-[13px] font-bold text-white hover:bg-primary/90 disabled:opacity-60">Lưu giá</button></div></div></div>, document.body);
}
